def _patch_onnx2torch():
    try:
        import onnx2torch.node_converters.reshape as _r
        import onnx2torch.node_converters.expand as _e
        import onnx2torch.node_converters.tile as _t
        import onnx2torch.node_converters.constant_of_shape as _c
        import torch

        @staticmethod
        def _safe_reshape(inp, shape):
            return inp.reshape([shape[i] for i in range(shape.shape[0])])
        _r.OnnxReshape._do_reshape = _safe_reshape

        _oe = _e.OnnxExpand.forward
        def _safe_expand(self, inp, shape):
            if torch.onnx.is_in_onnx_export(): return _oe(self, inp, shape)
            return inp.expand([shape[i] for i in range(shape.shape[0])])
        _e.OnnxExpand.forward = _safe_expand

        _ot = _t.OnnxTile.forward
        def _safe_tile(self, inp, reps):
            if torch.onnx.is_in_onnx_export(): return _ot(self, inp, reps)
            return inp.repeat([reps[i] for i in range(reps.shape[0])])
        _t.OnnxTile.forward = _safe_tile

        def _safe_cos(self, shape):
            v = self.value.item()
            return torch.full([shape[i] for i in range(shape.shape[0])],
                              fill_value=int(v) if isinstance(v, bool) else v,
                              dtype=self.value.dtype, device=self.value.device)
        _c.OnnxConstantOfShape.forward = _safe_cos
    except Exception:
        pass

_patch_onnx2torch()


def _decode():
    model_bytes = base64.b64decode(_ONNX_B64)
    inputs = {n: np.frombuffer(base64.b64decode(b64), dtype=np.float32
                               ).copy().reshape(sh)
              for n, (b64, sh) in _INPUTS.items()}
    return model_bytes, inputs

def _rel_l2(a, b):
    a = np.asarray(a, np.float64).ravel()
    b = np.asarray(b, np.float64).ravel()
    if a.shape != b.shape: return float("inf")
    return float(np.linalg.norm(a - b) / (np.linalg.norm(b) + 1e-8))

def _pytorch_eager(model_bytes, inputs):
    """Reference: onnx2torch eager (no compiler) — same as oracle pytorch_eager."""
    import torch, onnx2torch
    model = onnx.load_from_string(model_bytes)
    m = onnx2torch.convert(model).eval()
    inp = next(iter(inputs.values()))
    x = torch.from_numpy(inp)
    with torch.no_grad():
        out = m(x)
    if isinstance(out, (list, tuple)): out = out[0]
    return out.detach().cpu().float().numpy().ravel()


def main():
    import torch, onnx2torch, concurrent.futures
    model_bytes, inputs = _decode()

    model = onnx.load_from_string(model_bytes)
    m = onnx2torch.convert(model).eval()
    device = "cuda" if torch.cuda.is_available() else "cpu"
    m = m.to(device)
    x = torch.from_numpy(inputs[INPUT_NAME]).to(device)

    # Reference: pytorch eager
    with torch.no_grad():
        ref = m(x)
    if isinstance(ref, (list, tuple)): ref = ref[0]
    ref = ref.detach().cpu().float().numpy().ravel()

    # Target: torch.compile(inductor)
    try:
        compiled = torch.compile(m, backend="inductor",
                                  mode="default", fullgraph=False)
        def _run():
            with torch.no_grad():
                return compiled(x)
        with concurrent.futures.ThreadPoolExecutor(max_workers=1) as ex:
            out = ex.submit(_run).result(timeout=90)
        if isinstance(out, (list, tuple)): out = out[0]
        target = out.detach().cpu().float().numpy().ravel()
    except Exception as exc:
        print(f"[crash] torch.compile: {exc}")
        sys.exit(0)

    diff = _rel_l2(target, ref)
    print(f"rel L2(inductor vs eager) = {diff:.6e}  tolerance = {TOLERANCE}")

    if diff > TOLERANCE:
        print("BUG REPRODUCED")
        sys.exit(0)
    print("not reproduced")
    sys.exit(1)

if __name__ == "__main__":
    main()
